using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;
using System;
using System.Collections.Generic;

namespace ContosoUniversity.Tests.Helpers
{
    public static class TestDbContextFactory
    {
        public static SchoolContext Create(string databaseName = null)
        {
            databaseName ??= Guid.NewGuid().ToString();
            var options = new DbContextOptionsBuilder<SchoolContext>()
                .UseInMemoryDatabase(databaseName)
                .Options;

            var context = new SchoolContext(options);
            context.Database.EnsureCreated();
            return context;
        }

        public static SchoolContext CreateWithSeedData(string databaseName = null)
        {
            var context = Create(databaseName);
            SeedData(context);
            return context;
        }

        private static void SeedData(SchoolContext context)
        {
            var departments = new[]
            {
                new Department { DepartmentID = 1, Name = "Engineering", Budget = 350000m, StartDate = new DateTime(2020, 9, 1), RowVersion = new byte[] { 0, 0, 0, 1 } },
                new Department { DepartmentID = 2, Name = "Mathematics", Budget = 100000m, StartDate = new DateTime(2020, 9, 1), RowVersion = new byte[] { 0, 0, 0, 2 } },
                new Department { DepartmentID = 3, Name = "English", Budget = 200000m, StartDate = new DateTime(2021, 1, 15), RowVersion = new byte[] { 0, 0, 0, 3 } }
            };
            context.Departments.AddRange(departments);

            var instructors = new[]
            {
                new Instructor { ID = 1, FirstMidName = "Kim", LastName = "Abercrombie", HireDate = new DateTime(2015, 3, 11), CourseAssignments = new List<CourseAssignment>() },
                new Instructor { ID = 2, FirstMidName = "Fadi", LastName = "Fakhouri", HireDate = new DateTime(2018, 7, 6), CourseAssignments = new List<CourseAssignment>() }
            };
            context.Instructors.AddRange(instructors);

            var courses = new[]
            {
                new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
                new Course { CourseID = 4022, Title = "Microeconomics", Credits = 3, DepartmentID = 2 },
                new Course { CourseID = 2021, Title = "Composition", Credits = 3, DepartmentID = 3 }
            };
            context.Courses.AddRange(courses);

            var students = new[]
            {
                new Student { ID = 10, FirstMidName = "Carson", LastName = "Alexander", EnrollmentDate = new DateTime(2019, 9, 1), Enrollments = new List<Enrollment>() },
                new Student { ID = 11, FirstMidName = "Meredith", LastName = "Alonso", EnrollmentDate = new DateTime(2020, 9, 1), Enrollments = new List<Enrollment>() },
                new Student { ID = 12, FirstMidName = "Arturo", LastName = "Anand", EnrollmentDate = new DateTime(2019, 9, 1), Enrollments = new List<Enrollment>() }
            };
            context.Students.AddRange(students);

            var enrollments = new[]
            {
                new Enrollment { EnrollmentID = 1, StudentID = 10, CourseID = 1050, Grade = Grade.A },
                new Enrollment { EnrollmentID = 2, StudentID = 11, CourseID = 4022, Grade = Grade.B },
                new Enrollment { EnrollmentID = 3, StudentID = 12, CourseID = 2021, Grade = Grade.C }
            };
            context.Enrollments.AddRange(enrollments);

            context.SaveChanges();
        }
    }
}

using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Services
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        private NotificationService _sut;

        [TestInitialize]
        public void Setup()
        {
            _sut = new NotificationService();
            // Drain any leftover notifications from previous tests (shared static queue)
            while (_sut.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
        }

        [TestMethod]
        [DataRow(EntityOperation.CREATE, "New Student 'John Doe' has been created")]
        [DataRow(EntityOperation.UPDATE, "Student 'John Doe' has been updated")]
        [DataRow(EntityOperation.DELETE, "Student 'John Doe' has been deleted")]
        public void SendNotification_WithDisplayName_GeneratesCorrectMessage(EntityOperation operation, string expectedMessage)
        {
            // Act
            _sut.SendNotification("Student", "1", "John Doe", operation, "Admin");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual(expectedMessage, notification.Message);
        }

        [TestMethod]
        [DataRow(EntityOperation.CREATE, "New Course (ID: 101) has been created")]
        [DataRow(EntityOperation.UPDATE, "Course (ID: 101) has been updated")]
        [DataRow(EntityOperation.DELETE, "Course (ID: 101) has been deleted")]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage(EntityOperation operation, string expectedMessage)
        {
            // Act
            _sut.SendNotification("Course", "101", operation, "Admin");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual(expectedMessage, notification.Message);
        }

        [TestMethod]
        public void SendNotification_SetsAllProperties()
        {
            // Act
            _sut.SendNotification("Student", "42", "Test Student", EntityOperation.CREATE, "TestUser");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("42", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("TestUser", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
            Assert.IsNull(notification.ReadAt);
        }

        [TestMethod]
        public void SendNotification_NullUserName_DefaultsToSystem()
        {
            // Act
            _sut.SendNotification("Course", "1", EntityOperation.UPDATE, null);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            // Act
            var result = _sut.ReceiveNotification();

            // Assert
            Assert.IsNull(result);
        }

        [TestMethod]
        public void ReceiveNotification_DequeuesInFifoOrder()
        {
            // Arrange
            _sut.SendNotification("Student", "1", "First", EntityOperation.CREATE);
            _sut.SendNotification("Student", "2", "Second", EntityOperation.UPDATE);

            // Act & Assert
            var first = _sut.ReceiveNotification();
            Assert.AreEqual("1", first.EntityId);

            var second = _sut.ReceiveNotification();
            Assert.AreEqual("2", second.EntityId);

            var third = _sut.ReceiveNotification();
            Assert.IsNull(third);
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op for in-memory queue; just verify no exceptions
            _sut.MarkAsRead(1);
            _sut.MarkAsRead(999);
        }

        [TestMethod]
        public void SendNotification_OverloadsProduceSameResult()
        {
            // Act - two-param overload (no display name)
            _sut.SendNotification("Dept", "5", EntityOperation.DELETE, "User1");
            var notification = _sut.ReceiveNotification();

            // Assert
            Assert.IsNotNull(notification);
            Assert.AreEqual("Dept (ID: 5) has been deleted", notification.Message);
        }

        [TestMethod]
        public void Dispose_CanBeCalledMultipleTimes()
        {
            // Verify multiple dispose calls don't throw
            _sut.Dispose();
            _sut.Dispose();
        }
    }
}

using System;
using System.Collections.Generic;
using System.Linq;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class PaginatedListTests
    {
        [TestMethod]
        public void Create_FirstPage_ReturnsCorrectItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

            // Assert
            Assert.AreEqual(10, result.Count);
            Assert.AreEqual(1, result[0]);
            Assert.AreEqual(10, result[9]);
        }

        [TestMethod]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, pageIndex: 3, pageSize: 10);

            // Assert
            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(21, result[0]);
            Assert.AreEqual(25, result[4]);
        }

        [TestMethod]
        public void Create_CalculatesTotalPagesCorrectly()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

            // Assert
            Assert.AreEqual(3, result.TotalPages);
        }

        [TestMethod]
        [DataRow(1, 10, 1, false, DisplayName = "First page has no previous")]
        [DataRow(25, 10, 2, true, DisplayName = "Second page has previous")]
        [DataRow(25, 10, 3, true, DisplayName = "Last page has previous")]
        public void HasPreviousPage_ReturnsCorrectValue(int totalItems, int pageSize, int pageIndex, bool expected)
        {
            // Arrange
            var source = Enumerable.Range(1, totalItems).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, pageIndex, pageSize);

            // Assert
            Assert.AreEqual(expected, result.HasPreviousPage);
        }

        [TestMethod]
        [DataRow(25, 10, 1, true, DisplayName = "First page has next")]
        [DataRow(25, 10, 2, true, DisplayName = "Middle page has next")]
        [DataRow(25, 10, 3, false, DisplayName = "Last page has no next")]
        public void HasNextPage_ReturnsCorrectValue(int totalItems, int pageSize, int pageIndex, bool expected)
        {
            // Arrange
            var source = Enumerable.Range(1, totalItems).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, pageIndex, pageSize);

            // Assert
            Assert.AreEqual(expected, result.HasNextPage);
        }

        [TestMethod]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            // Arrange
            var source = Enumerable.Empty<int>().AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

            // Assert
            Assert.AreEqual(0, result.Count);
            Assert.AreEqual(0, result.TotalPages);
            Assert.IsFalse(result.HasPreviousPage);
            Assert.IsFalse(result.HasNextPage);
        }

        [TestMethod]
        public void Create_ExactlyOnePage_NoNextOrPrevious()
        {
            // Arrange
            var source = Enumerable.Range(1, 10).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

            // Assert
            Assert.AreEqual(10, result.Count);
            Assert.AreEqual(1, result.TotalPages);
            Assert.IsFalse(result.HasPreviousPage);
            Assert.IsFalse(result.HasNextPage);
        }

        [TestMethod]
        public void Constructor_SetsPageIndex()
        {
            // Arrange & Act
            var list = new PaginatedList<string>(new List<string> { "a", "b" }, count: 20, pageIndex: 3, pageSize: 5);

            // Assert
            Assert.AreEqual(3, list.PageIndex);
            Assert.AreEqual(4, list.TotalPages);
        }

        [TestMethod]
        public void Create_PageSizeOfOne_CreatesCorrectPages()
        {
            // Arrange
            var source = Enumerable.Range(1, 5).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, pageIndex: 3, pageSize: 1);

            // Assert
            Assert.AreEqual(1, result.Count);
            Assert.AreEqual(3, result[0]);
            Assert.AreEqual(5, result.TotalPages);
            Assert.IsTrue(result.HasPreviousPage);
            Assert.IsTrue(result.HasNextPage);
        }
    }
}

