using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Services
{
    [TestClass]
    public sealed class NotificationServiceTests
    {
        private NotificationService _sut;

        [TestInitialize]
        public void Setup()
        {
            _sut = new NotificationService();
            // Drain any leftover notifications from previous tests (shared static queue)
            while (_sut.ReceiveNotification() != null) { }
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
        }

        [TestMethod]
        [DataRow(EntityOperation.CREATE, "New Student 'John Doe' has been created")]
        [DataRow(EntityOperation.UPDATE, "Student 'John Doe' has been updated")]
        [DataRow(EntityOperation.DELETE, "Student 'John Doe' has been deleted")]
        public void SendNotification_WithDisplayName_GeneratesCorrectMessage(EntityOperation operation, string expectedMessage)
        {
            // Act
            _sut.SendNotification("Student", "1", "John Doe", operation, "Admin");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual(expectedMessage, notification.Message);
        }

        [TestMethod]
        [DataRow(EntityOperation.CREATE, "New Course (ID: 101) has been created")]
        [DataRow(EntityOperation.UPDATE, "Course (ID: 101) has been updated")]
        [DataRow(EntityOperation.DELETE, "Course (ID: 101) has been deleted")]
        public void SendNotification_WithoutDisplayName_UsesIdInMessage(EntityOperation operation, string expectedMessage)
        {
            // Act
            _sut.SendNotification("Course", "101", operation, "Admin");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual(expectedMessage, notification.Message);
        }

        [TestMethod]
        public void SendNotification_SetsAllProperties()
        {
            // Act
            _sut.SendNotification("Student", "42", "Test Student", EntityOperation.CREATE, "TestUser");

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("Student", notification.EntityType);
            Assert.AreEqual("42", notification.EntityId);
            Assert.AreEqual("CREATE", notification.Operation);
            Assert.AreEqual("TestUser", notification.CreatedBy);
            Assert.IsFalse(notification.IsRead);
            Assert.IsNull(notification.ReadAt);
        }

        [TestMethod]
        public void SendNotification_NullUserName_DefaultsToSystem()
        {
            // Act
            _sut.SendNotification("Course", "1", EntityOperation.UPDATE, null);

            // Assert
            var notification = _sut.ReceiveNotification();
            Assert.IsNotNull(notification);
            Assert.AreEqual("System", notification.CreatedBy);
        }

        [TestMethod]
        public void ReceiveNotification_EmptyQueue_ReturnsNull()
        {
            // Act
            var result = _sut.ReceiveNotification();

            // Assert
            Assert.IsNull(result);
        }

        [TestMethod]
        public void ReceiveNotification_DequeuesInFifoOrder()
        {
            // Arrange
            _sut.SendNotification("Student", "1", "First", EntityOperation.CREATE);
            _sut.SendNotification("Student", "2", "Second", EntityOperation.UPDATE);

            // Act & Assert
            var first = _sut.ReceiveNotification();
            Assert.AreEqual("1", first.EntityId);

            var second = _sut.ReceiveNotification();
            Assert.AreEqual("2", second.EntityId);

            var third = _sut.ReceiveNotification();
            Assert.IsNull(third);
        }

        [TestMethod]
        public void MarkAsRead_DoesNotThrow()
        {
            // MarkAsRead is a no-op for in-memory queue; just verify no exceptions
            _sut.MarkAsRead(1);
            _sut.MarkAsRead(999);
        }

        [TestMethod]
        public void SendNotification_OverloadsProduceSameResult()
        {
            // Act - two-param overload (no display name)
            _sut.SendNotification("Dept", "5", EntityOperation.DELETE, "User1");
            var notification = _sut.ReceiveNotification();

            // Assert
            Assert.IsNotNull(notification);
            Assert.AreEqual("Dept (ID: 5) has been deleted", notification.Message);
        }

        [TestMethod]
        public void Dispose_CanBeCalledMultipleTimes()
        {
            // Verify multiple dispose calls don't throw
            _sut.Dispose();
            _sut.Dispose();
        }
    }
}

