using System;
using System.Collections.Generic;
using System.Linq;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests
{
    [TestClass]
    public sealed class PaginatedListTests
    {
        [TestMethod]
        public void Create_FirstPage_ReturnsCorrectItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

            // Assert
            Assert.AreEqual(10, result.Count);
            Assert.AreEqual(1, result[0]);
            Assert.AreEqual(10, result[9]);
        }

        [TestMethod]
        public void Create_LastPage_ReturnsRemainingItems()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, pageIndex: 3, pageSize: 10);

            // Assert
            Assert.AreEqual(5, result.Count);
            Assert.AreEqual(21, result[0]);
            Assert.AreEqual(25, result[4]);
        }

        [TestMethod]
        public void Create_CalculatesTotalPagesCorrectly()
        {
            // Arrange
            var source = Enumerable.Range(1, 25).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

            // Assert
            Assert.AreEqual(3, result.TotalPages);
        }

        [TestMethod]
        [DataRow(1, 10, 1, false, DisplayName = "First page has no previous")]
        [DataRow(25, 10, 2, true, DisplayName = "Second page has previous")]
        [DataRow(25, 10, 3, true, DisplayName = "Last page has previous")]
        public void HasPreviousPage_ReturnsCorrectValue(int totalItems, int pageSize, int pageIndex, bool expected)
        {
            // Arrange
            var source = Enumerable.Range(1, totalItems).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, pageIndex, pageSize);

            // Assert
            Assert.AreEqual(expected, result.HasPreviousPage);
        }

        [TestMethod]
        [DataRow(25, 10, 1, true, DisplayName = "First page has next")]
        [DataRow(25, 10, 2, true, DisplayName = "Middle page has next")]
        [DataRow(25, 10, 3, false, DisplayName = "Last page has no next")]
        public void HasNextPage_ReturnsCorrectValue(int totalItems, int pageSize, int pageIndex, bool expected)
        {
            // Arrange
            var source = Enumerable.Range(1, totalItems).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, pageIndex, pageSize);

            // Assert
            Assert.AreEqual(expected, result.HasNextPage);
        }

        [TestMethod]
        public void Create_EmptySource_ReturnsEmptyList()
        {
            // Arrange
            var source = Enumerable.Empty<int>().AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

            // Assert
            Assert.AreEqual(0, result.Count);
            Assert.AreEqual(0, result.TotalPages);
            Assert.IsFalse(result.HasPreviousPage);
            Assert.IsFalse(result.HasNextPage);
        }

        [TestMethod]
        public void Create_ExactlyOnePage_NoNextOrPrevious()
        {
            // Arrange
            var source = Enumerable.Range(1, 10).AsQueryable();

            // Act
            var result = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 10);

            // Assert
            Assert.AreEqual(10, result.Count);
            Assert.AreEqual(1, result.TotalPages);
            Assert.IsFalse(result.HasPreviousPage);
            Assert.IsFalse(result.HasNextPage);
        }

        [TestMethod]
        public void Constructor_SetsPageIndex()
        {
            // Arrange & Act
            var list = new PaginatedList<string>(new List<string> { "a", "b" }, count: 20, pageIndex: 3, pageSize: 5);

            // Assert
            Assert.AreEqual(3, list.PageIndex);
            Assert.AreEqual(4, list.TotalPages);
        }

        [TestMethod]
        public void Create_PageSizeOfOne_CreatesCorrectPages()
        {
            // Arrange
