using System;
using System.Linq;
using System.Net;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class StudentsControllerTests
    {
        private SchoolContext _context;
        private StudentsController _sut;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _sut = new StudentsController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
            _context?.Dispose();
        }

        #region Index

        [TestMethod]
        public void Index_NoParameters_ReturnsViewWithStudents()
        {
            // Act
            var result = _sut.Index(null, null, null, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(3, model.Count);
        }

        [TestMethod]
        public void Index_SortByNameDesc_ReturnsDescendingOrder()
        {
            // Act
            var result = _sut.Index("name_desc", null, null, null) as ViewResult;

            // Assert
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual("Anand", model[0].LastName);
            Assert.AreEqual("Alonso", model[1].LastName);
            Assert.AreEqual("Alexander", model[2].LastName);
        }

        [TestMethod]
        public void Index_SortByDate_ReturnsDateAscending()
        {
            // Act
            var result = _sut.Index("Date", null, null, null) as ViewResult;

            // Assert
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            // Alexander and Anand both have 2019-09-01, Alonso has 2020-09-01
            Assert.AreEqual(new DateTime(2020, 9, 1), model.Last().EnrollmentDate);
        }

        [TestMethod]
        public void Index_SortByDateDesc_ReturnsDateDescending()
        {
            // Act
            var result = _sut.Index("date_desc", null, null, null) as ViewResult;

            // Assert
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(new DateTime(2020, 9, 1), model.First().EnrollmentDate);
        }

        [TestMethod]
        public void Index_SearchString_FiltersResults()
        {
            // Act
            var result = _sut.Index(null, null, "Alexander", null) as ViewResult;

            // Assert
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Alexander", model[0].LastName);
        }

        [TestMethod]
        public void Index_SearchByFirstName_FiltersResults()
        {
            // Act
            var result = _sut.Index(null, null, "Meredith", null) as ViewResult;

            // Assert
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.Count);
            Assert.AreEqual("Alonso", model[0].LastName);
        }

        [TestMethod]
        public void Index_NewSearchString_ResetsPageToOne()
        {
            // Act
            var result = _sut.Index(null, null, "Alexander", 5) as ViewResult;

            // Assert - searchString not null so page should be reset
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.PageIndex);
        }

        [TestMethod]
        public void Index_NullSearchString_UsesCurrentFilter()
        {
            // Act
            var result = _sut.Index(null, "Alexander", null, 1) as ViewResult;

            // Assert
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual(1, model.Count);
        }

        [TestMethod]
        public void Index_DefaultSort_OrdersByLastNameAscending()
        {
            // Act
            var result = _sut.Index(null, null, null, null) as ViewResult;

            // Assert
            var model = result.Model as PaginatedList<Student>;
            Assert.IsNotNull(model);
            Assert.AreEqual("Alexander", model[0].LastName);
            Assert.AreEqual("Alonso", model[1].LastName);
            Assert.AreEqual("Anand", model[2].LastName);
        }

        #endregion

        #region Details

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _sut.Details(null) as StatusCodeResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithStudent()
        {
            // Act
            var result = _sut.Details(10) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var student = result.Model as Student;
            Assert.IsNotNull(student);
            Assert.AreEqual("Alexander", student.LastName);
        }

        #endregion

        #region Create GET

        [TestMethod]
        public void Create_Get_ReturnsViewWithDefaultDate()
        {
            // Act
            var result = _sut.Create() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var student = result.Model as Student;
            Assert.IsNotNull(student);
            Assert.AreEqual(DateTime.Today, student.EnrollmentDate);
        }

        #endregion

        #region Create POST

        [TestMethod]
        public void Create_Post_ValidStudent_RedirectsToIndex()
        {
            // Arrange
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            // Act
            var result = _sut.Create(student) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(4, _context.Students.Count());
        }

        [TestMethod]
        public void Create_Post_MinDateEnrollment_AddsModelError()
        {
            // Arrange
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = DateTime.MinValue
            };

            // Act
            var result = _sut.Create(student) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsFalse(_sut.ModelState.IsValid);
            Assert.IsTrue(_sut.ModelState.ContainsKey("EnrollmentDate"));
        }

        [TestMethod]
        public void Create_Post_DateBefore1753_AddsModelError()
        {
            // Arrange
            var student = new Student
            {
                FirstMidName = "Test",
                LastName = "Student",
                EnrollmentDate = new DateTime(1752, 12, 31)
            };

            // Act
            var result = _sut.Create(student) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsTrue(_sut.ModelState.ContainsKey("EnrollmentDate"));
        }

        [TestMethod]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            // Arrange
            _sut.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                FirstMidName = "Test",
                EnrollmentDate = new DateTime(2023, 9, 1)
            };

            // Act
            var result = _sut.Create(student) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreSame(student, result.Model);
        }

        #endregion

        #region Edit GET

        [TestMethod]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _sut.Edit((int?)null) as StatusCodeResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Edit_Get_InvalidId_ReturnsNotFound()
        {
            // Act
            var result = _sut.Edit(999) as NotFoundResult;

            // Assert
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Edit_Get_ValidId_ReturnsViewWithStudent()
        {
            // Act
            var result = _sut.Edit(10) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var student = result.Model as Student;
            Assert.IsNotNull(student);
            Assert.AreEqual("Alexander", student.LastName);
        }

        #endregion

        #region Edit POST

        [TestMethod]
        public void Edit_Post_ValidStudent_RedirectsToIndex()
        {
            // Arrange
            var student = _context.Students.Find(10);
            _context.Entry(student).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var updatedStudent = new Student
            {
                ID = 10,
                FirstMidName = "Carson",
                LastName = "UpdatedName",
                EnrollmentDate = new DateTime(2019, 9, 1)
            };

            // Act
            var result = _sut.Edit(updatedStudent) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

        [TestMethod]
        public void Edit_Post_MinDateEnrollment_AddsModelError()
        {
            // Arrange
            var student = new Student
            {
                ID = 10,
                FirstMidName = "Carson",
                LastName = "Alexander",
                EnrollmentDate = DateTime.MinValue
            };

            // Act
            var result = _sut.Edit(student) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.IsTrue(_sut.ModelState.ContainsKey("EnrollmentDate"));
        }

        [TestMethod]
        public void Edit_Post_InvalidModelState_ReturnsView()
        {
            // Arrange
            _sut.ModelState.AddModelError("LastName", "Required");
            var student = new Student
            {
                ID = 10,
                FirstMidName = "Carson",
                LastName = "",
                EnrollmentDate = new DateTime(2019, 9, 1)
            };

            // Act
            var result = _sut.Edit(student) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
        }

        #endregion

        #region Delete GET

        [TestMethod]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _sut.Delete(null) as StatusCodeResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            // Act
            var result = _sut.Delete(999) as NotFoundResult;

            // Assert
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Delete_Get_ValidId_ReturnsViewWithStudent()
        {
            // Act
            var result = _sut.Delete(10) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var student = result.Model as Student;
            Assert.IsNotNull(student);
            Assert.AreEqual("Alexander", student.LastName);
        }

        #endregion

        #region Delete POST

        [TestMethod]
        public void DeleteConfirmed_RemovesStudentAndRedirects()
        {
            // Act
            var result = _sut.DeleteConfirmed(10) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(2, _context.Students.Count());
        }

        #endregion
    }
}

