using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class DepartmentsControllerTests
    {
        private SchoolContext _context;
        private DepartmentsController _sut;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _sut = new DepartmentsController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
            _context?.Dispose();
        }

        #region Index

        [TestMethod]
        public void Index_ReturnsViewWithAllDepartments()
        {
            // Act
            var result = _sut.Index() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as List<Department>;
            Assert.IsNotNull(model);
            Assert.AreEqual(3, model.Count);
        }

        #endregion

        #region Details

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _sut.Details(null) as StatusCodeResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Details_InvalidId_ReturnsNotFound()
        {
            // Act
            var result = _sut.Details(999) as NotFoundResult;

            // Assert
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithDepartment()
        {
            // Act
            var result = _sut.Details(1) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var department = result.Model as Department;
            Assert.IsNotNull(department);
            Assert.AreEqual("Engineering", department.Name);
        }

        #endregion

        #region Create GET

        [TestMethod]
        public void Create_Get_ReturnsView()
        {
            // Act
            var result = _sut.Create() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
        }

        #endregion

        #region Create POST

        [TestMethod]
        public void Create_Post_ValidDepartment_RedirectsToIndex()
        {
            // Arrange
            var department = new Department
            {
                Name = "Physics",
                Budget = 150000m,
                StartDate = new DateTime(2023, 1, 1)
            };

            // Act
            var result = _sut.Create(department) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(4, _context.Departments.Count());
        }

        [TestMethod]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            // Arrange
            _sut.ModelState.AddModelError("Name", "Required");
            var department = new Department { Budget = 100000m, StartDate = DateTime.Now };

            // Act
            var result = _sut.Create(department) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
        }

        #endregion

