        {
            // Act
            var result = _sut.Edit(999) as NotFoundResult;

            // Assert
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Edit_Get_ValidId_ReturnsViewWithDepartment()
        {
            // Act
            var result = _sut.Edit(1) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var department = result.Model as Department;
            Assert.IsNotNull(department);
            Assert.AreEqual("Engineering", department.Name);
        }

        #endregion

        #region Edit POST

        [TestMethod]
        public void Edit_Post_ValidDepartment_RedirectsToIndex()
        {
            // Arrange
            var dept = _context.Departments.Find(1);
            _context.Entry(dept).State = Microsoft.EntityFrameworkCore.EntityState.Detached;

            var updatedDept = new Department
            {
                DepartmentID = 1,
                Name = "Updated Engineering",
                Budget = 400000m,
                StartDate = new DateTime(2020, 9, 1),
                RowVersion = new byte[] { 0, 0, 0, 1 }
            };

            // Act
            var result = _sut.Edit(updatedDept) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
        }

