            var department = new Department
            {
                DepartmentID = 1,
                Name = "",
                Budget = 100000m,
                StartDate = DateTime.Now,
                RowVersion = new byte[] { 0, 0, 0, 1 }
            };

            // Act
            var result = _sut.Edit(department) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
        }

        #endregion

        #region Delete GET

        [TestMethod]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _sut.Delete(null) as StatusCodeResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            // Act
            var result = _sut.Delete(999) as NotFoundResult;

            // Assert
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Delete_Get_ValidId_ReturnsViewWithDepartment()
        {
            // Act
            var result = _sut.Delete(1) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var department = result.Model as Department;
            Assert.IsNotNull(department);
            Assert.AreEqual("Engineering", department.Name);
        }

        #endregion

        #region Delete POST

        [TestMethod]
        public void DeleteConfirmed_RemovesDepartmentAndRedirects()
        {
            // Act
            var result = _sut.DeleteConfirmed(1) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(2, _context.Departments.Count());
