using System;
using System.Collections.Generic;
using System.Linq;
using System.Net;
using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;
using Microsoft.VisualStudio.TestTools.UnitTesting;

namespace ContosoUniversity.Tests.Controllers
{
    [TestClass]
    public sealed class InstructorsControllerTests
    {
        private SchoolContext _context;
        private InstructorsController _sut;

        [TestInitialize]
        public void Setup()
        {
            _context = TestDbContextFactory.CreateWithSeedData();
            _sut = new InstructorsController(_context);
        }

        [TestCleanup]
        public void Cleanup()
        {
            _sut?.Dispose();
            _context?.Dispose();
        }

        #region Index

        [TestMethod]
        public void Index_NoParameters_ReturnsViewWithInstructors()
        {
            // Act
            var result = _sut.Index(null, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Models.SchoolViewModels.InstructorIndexData;
            Assert.IsNotNull(model);
            Assert.AreEqual(2, model.Instructors.Count());
        }

        [TestMethod]
        public void Index_WithInstructorId_PopulatesCourses()
        {
            // Arrange - add a course assignment
            var courseAssignment = new CourseAssignment { InstructorID = 1, CourseID = 1050 };
            _context.CourseAssignments.Add(courseAssignment);
            _context.SaveChanges();

            // Recreate controller with updated context
            _sut.Dispose();
            _sut = new InstructorsController(_context);

            // Act
            var result = _sut.Index(1, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var model = result.Model as Models.SchoolViewModels.InstructorIndexData;
            Assert.IsNotNull(model);
            Assert.IsNotNull(model.Courses);
            Assert.AreEqual(1, model.Courses.Count());
        }

        #endregion

        #region Details

        [TestMethod]
        public void Details_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _sut.Details(null) as StatusCodeResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Details_InvalidId_ReturnsNotFound()
        {
            // Act
            var result = _sut.Details(999) as NotFoundResult;

            // Assert
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Details_ValidId_ReturnsViewWithInstructor()
        {
            // Act
            var result = _sut.Details(1) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var instructor = result.Model as Instructor;
            Assert.IsNotNull(instructor);
            Assert.AreEqual("Abercrombie", instructor.LastName);
        }

        #endregion

        #region Create GET

        [TestMethod]
        public void Create_Get_ReturnsViewWithInstructor()
        {
            // Act
            var result = _sut.Create() as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var instructor = result.Model as Instructor;
            Assert.IsNotNull(instructor);
            Assert.IsNotNull(instructor.CourseAssignments);
        }

        #endregion

        #region Create POST

        [TestMethod]
        public void Create_Post_ValidInstructor_RedirectsToIndex()
        {
            // Arrange
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = new DateTime(2023, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            // Act
            var result = _sut.Create(instructor, null) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(3, _context.Instructors.Count());
        }

        [TestMethod]
        public void Create_Post_WithSelectedCourses_AddsCourseAssignments()
        {
            // Arrange
            var instructor = new Instructor
            {
                FirstMidName = "New",
                LastName = "Instructor",
                HireDate = new DateTime(2023, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            // Act
            var result = _sut.Create(instructor, new[] { "1050", "4022" }) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            var savedInstructor = _context.Instructors
                .Where(i => i.LastName == "Instructor")
                .Single();
            var assignments = _context.CourseAssignments
                .Where(ca => ca.InstructorID == savedInstructor.ID)
                .ToList();
            Assert.AreEqual(2, assignments.Count);
        }

        [TestMethod]
        public void Create_Post_InvalidModelState_ReturnsView()
        {
            // Arrange
            _sut.ModelState.AddModelError("LastName", "Required");
            var instructor = new Instructor
            {
                FirstMidName = "New",
                HireDate = new DateTime(2023, 1, 1),
                CourseAssignments = new List<CourseAssignment>()
            };

            // Act
            var result = _sut.Create(instructor, null) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
        }

        #endregion

        #region Edit GET

        [TestMethod]
        public void Edit_Get_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _sut.Edit((int?)null) as StatusCodeResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        #endregion

        #region Delete GET

        [TestMethod]
        public void Delete_Get_NullId_ReturnsBadRequest()
        {
            // Act
            var result = _sut.Delete(null) as StatusCodeResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual((int)HttpStatusCode.BadRequest, result.StatusCode);
        }

        [TestMethod]
        public void Delete_Get_InvalidId_ReturnsNotFound()
        {
            // Act
            var result = _sut.Delete(999) as NotFoundResult;

            // Assert
            Assert.IsNotNull(result);
        }

        [TestMethod]
        public void Delete_Get_ValidId_ReturnsViewWithInstructor()
        {
            // Act
            var result = _sut.Delete(1) as ViewResult;

            // Assert
            Assert.IsNotNull(result);
            var instructor = result.Model as Instructor;
            Assert.IsNotNull(instructor);
            Assert.AreEqual("Abercrombie", instructor.LastName);
        }

        #endregion

        #region Delete POST

        [TestMethod]
        public void DeleteConfirmed_RemovesInstructorAndRedirects()
        {
            // Arrange - add office assignment
            _context.OfficeAssignments.Add(new OfficeAssignment { InstructorID = 1, Location = "Room 101" });
            _context.SaveChanges();

            // Act
            var result = _sut.DeleteConfirmed(1) as RedirectToActionResult;

            // Assert
            Assert.IsNotNull(result);
            Assert.AreEqual("Index", result.ActionName);
            Assert.AreEqual(1, _context.Instructors.Count());
        }

        [TestMethod]
        public void DeleteConfirmed_ClearsDepartmentAdministrator()
        {
            // Arrange
            var dept = _context.Departments.Find(1);
            dept.InstructorID = 1;
            _context.SaveChanges();

            // Act
            _sut.DeleteConfirmed(1);

            // Assert
            var updatedDept = _context.Departments.Find(1);
            Assert.IsNull(updatedDept.InstructorID);
        }

        #endregion
    }
}

